const rows = Array.from(document.querySelectorAll('.employee-flat-table .ant-table-tbody > tr.ant-table-row'));
const data = rows.map(tr => {
  const id = tr.getAttribute('data-row-key');
  const name = tr.querySelector('td:nth-child(2) .text-slate-700')?.innerText.trim() || '';
  const ldap = tr.querySelector('td:nth-child(2) span.font-mono')?.innerText.trim() || '';
  const departmentCode = tr.querySelector('td:nth-child(3) span.font-mono:first-child')?.innerText.trim() || '';
  const divisionCode = tr.querySelector('td:nth-child(3) span.font-mono:last-child')?.innerText.trim() || '';
  const role = tr.querySelector('td:nth-child(4) .pill')?.innerText.trim() || '';
  return { id, name, ldap, departmentCode, divisionCode, role };
}).filter(r => r.id);
automaSetVariable('scraped_employees', data);
automaNextBlock({ employees: data });
